	private void SelectArena(string fileName)
	{
		_selectedArena = fileName;
		((BaseButton)OverwriteButton).Disabled = false;
		MiniGameArenaInfo miniGameArenaInfo = _arenas.FirstOrDefault((MiniGameArenaInfo a) => a.FileName == fileName);
		if (miniGameArenaInfo != null)
		{
			DisplayNameEdit.Text = miniGameArenaInfo.DisplayName;
		}
	}

	private void ToggleShowSpawns()
	{
		_showingSpawns = !_showingSpawns;
		UpdateShowSpawnsText();
		this.OnShowSpawnsToggle?.Invoke();
	}

	public void SyncShowSpawns(bool showing)
	{
		_showingSpawns = showing;
		UpdateShowSpawnsText();
	}

	private void UpdateShowSpawnsText()
	{
		ShowSpawnsButton.Text = (_showingSpawns ? Loc.GetString("pubg-arena-hide-spawns") : Loc.GetString("pubg-arena-show-spawns"));
	}

	private void SaveNew()
	{
		string text = DisplayNameEdit.Text?.Trim();
		if (string.IsNullOrEmpty(text))
		{
			ValidationLabel.Text = Loc.GetString("pubg-arena-name-required");
			return;
		}
		if (_arenas.Count >= _maxArenas)
		{
			ValidationLabel.Text = Loc.GetString("pubg-arena-limit-reached");
			return;
		}
		this.OnSaveArena?.Invoke(text, arg2: false, null);
		DisplayNameEdit.Text = string.Empty;
		_selectedArena = null;
		((BaseButton)OverwriteButton).Disabled = true;
	}

	private void Overwrite()
	{
		string text = DisplayNameEdit.Text?.Trim();
		if (string.IsNullOrEmpty(text))
		{
			ValidationLabel.Text = Loc.GetString("pubg-arena-name-required");
		}
		else if (_selectedArena == null)
		{
			ValidationLabel.Text = Loc.GetString("pubg-arena-no-selection");
		}
		else
		{
			this.OnSaveArena?.Invoke(text, arg2: true, _selectedArena);
		}
	}

	private void UpdateValidation()
	{
		ValidationLabel.Text = string.Empty;
		int value = 0;
		int value2 = 0;
		string text = $"- {Loc.GetString("pubg-arena-req-team1")}: {value}\n";
		text += $"- {Loc.GetString("pubg-arena-req-team2")}: {value2}";
		RequirementsLabel.SetMessage(text, (Color?)null);
	}

	public void ShowError(string errorLocKey)
	{
		ValidationLabel.Text = Loc.GetString(errorLocKey);
	}

